const PI = 3.14159;      // 常量，不会变
let count = 0;            // 变量，会变

count = 1;  // OK
// PI = 3;  // ❌ 报错！const 不能重新赋值

// const 对象/数组的内容可以改，引用不能改
const user = { name: "小明" };
user.name = "小红";  // OK，修改属性
// user = {};  // ❌ 不能重新赋值

// 传统函数
function add(a, b) {
    return a + b;
}

// 箭头函数（等价）
const add = (a, b) => a + b;  // 单行可省略 return 和 {}

// 只有一个参数可省略括号
const double = x => x * 2;

// 多行还是要加 {}
const greet = (name) => {
    const msg = "你好，" + name;
    return msg;
};

console.log(add(3, 5));    // 8
console.log(double(4));   // 8
console.log(greet("小明"));  // 你好，小明

const name = "小明";
const age = 18;

// 传统拼接（繁琐）
console.log("我叫" + name + "，今年" + age + "岁");

// 模板字符串（优雅）
console.log(`我叫${name}，今年${age}岁`);

// 支持表达式
console.log(`1 + 1 = ${1 + 1}`);

// 支持多行
const html = `
    <div>
        <h2>${name}</h2>
        <p>${age} 岁</p>
    </div>
`;
console.log(html);

// 数组解构
const [a, b, c] = [1, 2, 3];
console.log(a, b, c);  // 1 2 3

// 跳过某些元素
const [first, , third] = [10, 20, 30];
console.log(first, third);  // 10 30

// 对象解构（变量名要和属性名一致）
const user = { name: "小明", age: 18, city: "北京" };
const { name, age } = user;
console.log(name, age);  // 小明 18

// 起别名
const { name: myName } = user;
console.log(myName);  // 小明

// 函数参数解构
function showUser({ name, age }) {
    console.log(`${name} 今年 ${age} 岁`);
}
showUser(user);

// 合并数组
const a = [1, 2, 3];
const b = [4, 5, 6];
const c = [...a, ...b];  // [1,2,3,4,5,6]

// 复制数组（不影响原数组）
const copy = [...a];

// 合并对象
const base = { color: "red", size: 10 };
const extra = { name: "圆", size: 20 };  // size 会覆盖
const merged = { ...base, ...extra };
// { color: "red", size: 20, name: "圆" }

// 函数收集剩余参数
function sum(...nums) {
    return nums.reduce((acc, n) => acc + n, 0);
}
console.log(sum(1, 2, 3, 4, 5));  // 15
